  1→import { broadcast } from './hub'
  2→import { readFile, writeFile, mkdir } from 'fs/promises'
  3→import { join } from 'path'
  4→import { existsSync } from 'fs'
  5→
  6→const AGENTS_DIR = join(import.meta.dir, '../../../agents')
  7→const MISSIONS_DIR = join(import.meta.dir, '../../../missions')
  8→const MCP_SERVER_PATH = join(import.meta.dir, '../mcp/server.ts')
  9→
 10→const running = new Map<string, ReturnType<typeof Bun.spawn>>()
 11→
 12→export function isRunning(agentId: string) {
 13→  return running.has(agentId)
 14→}
 15→
 16→export function getRunningAgents(): string[] {
 17→  return Array.from(running.keys())
 18→}
 19→
 20→export interface RunOptions {
 21→  workspace?: string
 22→  sessionId?: string
 23→  resume?: boolean
 24→}
 25→
 26→export async function runAgent(
 27→  agentId: string,
 28→  missionId: string,
 29→  prompt: string,
 30→  options: RunOptions = {}
 31→) {
 32→  if (running.has(agentId)) {
 33→    throw new Error(`Agent ${agentId} is already running`)
 34→  }
 35→
 36→  const profilePath = join(AGENTS_DIR, agentId, 'profile.json')
 37→  const profile = JSON.parse(await readFile(profilePath, 'utf-8'))
 38→
 39→  // Resolve workspace
 40→  let workspace = options.workspace
 41→  if (!workspace) {
 42→    try {
 43→      const statePath = join(MISSIONS_DIR, missionId, 'state.json')
 44→      const state = JSON.parse(await readFile(statePath, 'utf-8'))
 45→      workspace = state.workspace
 46→    } catch {}
 47→  }
 48→  if (!workspace && profile.default_workspace) {
 49→    workspace = profile.default_workspace.replace('~', process.env.HOME ?? '')
 50→  }
 51→  const cwd = workspace ?? process.cwd()
 52→
 53→  // Inject MCP config into workspace
 54→  await injectMcpConfig(cwd, agentId, missionId)
 55→
 56→  const driver = profile.driver
 57→  const systemPrompt = driver.system_prompt ?? ''
 58→
 59→  // Build full prompt = system prompt + task + artifacts dir
 60→  const artifactsDir = join(MISSIONS_DIR, missionId, 'artifacts')
 61→  await mkdir(artifactsDir, { recursive: true })
 62→
 63→  const fullPrompt = systemPrompt
 64→    ? `${systemPrompt}\n\n---\nMission ID: ${missionId}\nArtifacts directory: ${artifactsDir}\nSave ALL output files to the artifacts directory above.\nTask: ${prompt}`
 65→    : `Mission ID: ${missionId}\nArtifacts directory: ${artifactsDir}\nSave ALL output files to the artifacts directory above.\nTask: ${prompt}`
 66→
 67→  broadcast('agent:start', { agentId, missionId, workspace: cwd })
 68→
 69→  let cmd: string[]
 70→
 71→  if (driver.type === 'claude-code') {
 72→    // Build args, replacing {{full_prompt}} placeholder
 73→    const args = (driver.args as string[]).map((a: string) =>
 74→      a.replace('{{full_prompt}}', fullPrompt).replace('{{prompt}}', prompt)
 75→    )
 76→
 77→    // Inject session flags
 78→    if (options.sessionId) {
 79→      const insertAt = args.indexOf('-p')
 80→      if (insertAt !== -1) args.splice(insertAt, 0, '--resume', options.sessionId)
 81→    } else if (options.resume) {
 82→      const insertAt = args.indexOf('-p')
 83→      if (insertAt !== -1) args.splice(insertAt, 0, '--continue')
 84→    }
 85→
 86→    cmd = [driver.command, ...args]
 87→  } else if (driver.type === 'cli') {
 88→    // Legacy opencode-style
 89→    const args = (driver.args as string[]).map((a: string) =>
 90→      a.replace('{{prompt}}', fullPrompt)
 91→    )
 92→    if (driver.command === 'opencode' && (options.sessionId || options.resume)) {
 93→      const sessionFlags = options.sessionId ? ['-s', options.sessionId] : ['-c']
 94→      const [sub, ...rest] = args
 95→      cmd = [driver.command, sub, ...sessionFlags, ...rest]
 96→    } else {
 97→      cmd = [driver.command, ...args]
 98→    }
 99→  } else {
100→    cmd = ['claude', '--dangerously-skip-permissions', '-p', fullPrompt]
101→  }
102→
103→  const proc = Bun.spawn(cmd, {
104→    cwd,
105→    stdout: 'pipe',
106→    stderr: 'pipe',
107→    env: (() => {
108→      const env = { ...process.env }
109→      // Normalize: ANTHROPIC_AUTH_TOKEN (zshrc style) → ANTHROPIC_API_KEY (claude CLI expects)
110→      env.ANTHROPIC_API_KEY = process.env.ANTHROPIC_API_KEY ?? process.env.ANTHROPIC_AUTH_TOKEN ?? ''
111→      // Remove nested Claude Code session marker so agents can spawn claude
112→      delete env.CLAUDECODE
113→      delete env.CLAUDE_CODE_ENTRYPOINT
114→      return env
115→    })()
116→  })
117→
118→  running.set(agentId, proc)
119→
120→  // Stream stdout
121→  ;(async () => {
122→    const decoder = new TextDecoder()
123→    const reader = proc.stdout.getReader()
124→    try {
125→      while (true) {
126→        const { done, value } = await reader.read()
127→        if (done) break
128→        broadcast('agent:output', { agentId, missionId, text: decoder.decode(value) })
129→      }
130→    } finally { reader.releaseLock() }
131→  })()
132→
133→  // Stream stderr
134→  ;(async () => {
135→    const decoder = new TextDecoder()
136→    const reader = proc.stderr.getReader()
137→    try {
138→      while (true) {
139→        const { done, value } = await reader.read()
140→        if (done) break
141→        broadcast('agent:error', { agentId, missionId, text: decoder.decode(value) })
142→      }
143→    } finally { reader.releaseLock() }
144→  })()
145→
146→  proc.exited.then(async (code) => {
147→    running.delete(agentId)
148→
149→    // Capture opencode session ID
150→    let sessionId: string | undefined
151→    if (driver.command === 'opencode') {
152→      sessionId = await getLatestOpenCodeSession(cwd)
153→    }
154→
155→    // Persist session ID
156→    if (sessionId) {
157→      try {
158→        const statePath = join(MISSIONS_DIR, missionId, 'state.json')
159→        const state = JSON.parse(await readFile(statePath, 'utf-8'))
160→        state.sessions = state.sessions ?? {}
161→        state.sessions[agentId] = sessionId
162→        await writeFile(statePath, JSON.stringify(state, null, 2))
163→      } catch {}
164→    }
165→
166→    broadcast('agent:done', { agentId, missionId, exitCode: code, sessionId })
167→  })
168→}
169→
170→async function injectMcpConfig(cwd: string, agentId: string, missionId: string) {
171→  try {
172→    const claudeDir = join(cwd, '.claude')
173→    await mkdir(claudeDir, { recursive: true })
174→    const config = {
175→      mcpServers: {
176→        clawcorp: {
177→          command: 'bun',
178→          args: ['run', MCP_SERVER_PATH],
179→          env: {
180→            CLAWCORP_SERVER: 'http://localhost:3001',
181→            CLAWCORP_AGENT_ID: agentId,
182→            CLAWCORP_MISSION_ID: missionId,
183→            CLAWCORP_AGENTS_DIR: AGENTS_DIR,
184→            ...(process.env.ANTHROPIC_BASE_URL && { ANTHROPIC_BASE_URL: process.env.ANTHROPIC_BASE_URL }),
185→            ...(process.env.ANTHROPIC_AUTH_TOKEN && { ANTHROPIC_AUTH_TOKEN: process.env.ANTHROPIC_AUTH_TOKEN }),
186→            ...(process.env.ANTHROPIC_API_KEY && { ANTHROPIC_API_KEY: process.env.ANTHROPIC_API_KEY }),
187→          },
188→        },
189→      },
190→    }
191→    // Only write if not already present (don't override user config)
192→    const configPath = join(claudeDir, 'settings.json')
193→    if (existsSync(configPath)) {
194→      const existing = JSON.parse(await readFile(configPath, 'utf-8'))
195→      existing.mcpServers = { ...existing.mcpServers, ...config.mcpServers }
196→      await writeFile(configPath, JSON.stringify(existing, null, 2))
197→    } else {
198→      await writeFile(configPath, JSON.stringify(config, null, 2))
199→    }
200→  } catch (err) {
201→    console.error('[AgentRunner] Failed to inject MCP config:', err)
202→  }
203→}
204→
205→async function getLatestOpenCodeSession(cwd: string): Promise<string | undefined> {
206→  try {
207→    const proc = Bun.spawn(['opencode', 'session', 'list'], { cwd, stdout: 'pipe', stderr: 'pipe' })
208→    await proc.exited
209→    const text = await new Response(proc.stdout).text()
210→    const match = text.match(/([a-z0-9]{20,})/i)
211→    return match?.[1]
212→  } catch { return undefined }
213→}
214→
215→export function killAgent(agentId: string) {
216→  const proc = running.get(agentId)
217→  if (proc) {
218→    proc.kill()
219→    running.delete(agentId)
220→    broadcast('agent:killed', { agentId })
221→  }
222→}
223→

 1→import type { ServerWebSocket } from 'bun'
 2→
 3→const clients = new Set<ServerWebSocket<unknown>>()
 4→
 5→export function addClient(ws: ServerWebSocket<unknown>) {
 6→  clients.add(ws)
 7→}
 8→
 9→export function removeClient(ws: ServerWebSocket<unknown>) {
10→  clients.delete(ws)
11→}
12→
13→export function broadcast(event: string, data: unknown) {
14→  const msg = JSON.stringify({ event, data, ts: Date.now() })
15→  for (const ws of clients) {
16→    if (ws.readyState === 1) ws.send(msg)
17→  }
18→}
