 1→import { useEffect, useRef, useCallback } from 'react'
 2→
 3→export type WsMessage = {
 4→  event: string
 5→  data: Record<string, unknown>
 6→  ts: number
 7→}
 8→
 9→export function useWebSocket(onMessage: (msg: WsMessage) => void) {
10→  const ws = useRef<WebSocket | null>(null)
11→  const onMessageRef = useRef(onMessage)
12→  onMessageRef.current = onMessage
13→
14→  const connect = useCallback(() => {
15→    const socket = new WebSocket('ws://localhost:3001/ws')
16→
17→    socket.onopen = () => console.log('[WS] connected')
18→    socket.onclose = () => {
19→      console.log('[WS] disconnected, retrying in 2s...')
20→      setTimeout(connect, 2000)
21→    }
22→    socket.onerror = (e) => console.error('[WS] error', e)
23→    socket.onmessage = (e) => {
24→      try {
25→        const msg: WsMessage = JSON.parse(e.data)
26→        onMessageRef.current(msg)
27→      } catch {}
28→    }
29→
30→    ws.current = socket
31→  }, [])
32→
33→  useEffect(() => {
34→    connect()
35→    return () => ws.current?.close()
36→  }, [connect])
37→}
