  1→#!/usr/bin/env bun
  2→/**
  3→ * ClawCorp MCP Server (stdio transport)
  4→ * Spawned by Claude Code agents via .claude/settings.json
  5→ * Communicates with ClawCorp main server via HTTP
  6→ */
  7→import { Server } from '@modelcontextprotocol/sdk/server/index.js'
  8→import { StdioServerTransport } from '@modelcontextprotocol/sdk/server/stdio.js'
  9→import {
 10→  CallToolRequestSchema,
 11→  ListToolsRequestSchema,
 12→} from '@modelcontextprotocol/sdk/types.js'
 13→import { readFile, writeFile } from 'fs/promises'
 14→import { join } from 'path'
 15→
 16→const BASE_URL = process.env.CLAWCORP_SERVER ?? 'http://localhost:3001'
 17→const AGENT_ID = process.env.CLAWCORP_AGENT_ID ?? 'unknown'
 18→const MISSION_ID = process.env.CLAWCORP_MISSION_ID ?? 'unknown'
 19→const AGENTS_DIR = process.env.CLAWCORP_AGENTS_DIR ?? join(import.meta.dir, '../../../agents')
 20→
 21→async function api(method: string, path: string, body?: unknown) {
 22→  const res = await fetch(`${BASE_URL}${path}`, {
 23→    method,
 24→    headers: { 'Content-Type': 'application/json' },
 25→    body: body ? JSON.stringify(body) : undefined,
 26→  })
 27→  return res.json()
 28→}
 29→
 30→const server = new Server(
 31→  { name: 'clawcorp', version: '1.0.0' },
 32→  { capabilities: { tools: {} } }
 33→)
 34→
 35→server.setRequestHandler(ListToolsRequestSchema, async () => ({
 36→  tools: [
 37→    {
 38→      name: 'escalate',
 39→      description: 'Ask your supervisor when you are blocked. Do NOT use this for simple decisions — make assumptions instead. Only escalate genuine blockers.',
 40→      inputSchema: {
 41→        type: 'object',
 42→        properties: {
 43→          question: { type: 'string', description: 'The specific question or blocker' },
 44→          context: { type: 'string', description: 'Relevant context for the supervisor' },
 45→        },
 46→        required: ['question'],
 47→      },
 48→    },
 49→    {
 50→      name: 'delegate',
 51→      description: 'Assign a sub-task to one of your subordinate agents.',
 52→      inputSchema: {
 53→        type: 'object',
 54→        properties: {
 55→          agent_id: { type: 'string', description: 'ID of the subordinate agent' },
 56→          task: { type: 'string', description: 'Full task description for the agent' },
 57→          workspace: { type: 'string', description: 'Workspace directory for the task (optional)' },
 58→        },
 59→        required: ['agent_id', 'task'],
 60→      },
 61→    },
 62→    {
 63→      name: 'report',
 64→      description: 'Report task completion to your supervisor. Call this when your work is done.',
 65→      inputSchema: {
 66→        type: 'object',
 67→        properties: {
 68→          summary: { type: 'string', description: 'Summary of what was accomplished' },
 69→          artifacts: {
 70→            type: 'array',
 71→            items: { type: 'string' },
 72→            description: 'List of file paths created/modified',
 73→          },
 74→        },
 75→        required: ['summary'],
 76→      },
 77→    },
 78→    {
 79→      name: 'memory_read',
 80→      description: 'Read your long-term memory (past learnings and preferences).',
 81→      inputSchema: {
 82→        type: 'object',
 83→        properties: {},
 84→      },
 85→    },
 86→    {
 87→      name: 'memory_write',
 88→      description: 'Write to your long-term memory. Use this to save important learnings.',
 89→      inputSchema: {
 90→        type: 'object',
 91→        properties: {
 92→          content: { type: 'string', description: 'Content to append to memory' },
 93→        },
 94→        required: ['content'],
 95→      },
 96→    },
 97→    {
 98→      name: 'cross_team_delegate',
 99→      description: 'Delegate a task to another department\'s head with full context. Only callable by agents with rank "director" or "executive". Sends a structured context packet so the receiving team knows what to do, why, and what is already known.',
100→      inputSchema: {
101→        type: 'object',
102→        properties: {
103→          to_team: { type: 'string', description: 'Target team ID (e.g. "research-lab", "engineering")' },
104→          task: { type: 'string', description: 'What the receiving team should do' },
105→          why: { type: 'string', description: 'Why this is needed — business context' },
106→          known: { type: 'string', description: 'Relevant context, prior work, or constraints' },
107→          expected_output: { type: 'string', description: 'What format or type of result is expected' },
108→        },
109→        required: ['to_team', 'task', 'why', 'expected_output'],
110→      },
111→    },
112→  ],
113→}))
114→
115→server.setRequestHandler(CallToolRequestSchema, async (request) => {
116→  const { name, arguments: args } = request.params
117→  const a = (args ?? {}) as Record<string, unknown>
118→
119→  try {
120→    switch (name) {
121→      case 'escalate': {
122→        // Create escalation message
123→        const msg = await api('POST', '/api/messages', {
124→          from: AGENT_ID,
125→          missionId: MISSION_ID,
126→          type: 'escalate',
127→          question: a.question,
128→          context: a.context ?? '',
129→        })
130→
131→        // Poll for answer (max 10 minutes)
132→        const maxWait = 10 * 60 * 1000
133→        const interval = 4000
134→        const start = Date.now()
135→
136→        while (Date.now() - start < maxWait) {
137→          await Bun.sleep(interval)
138→          const updated = await api('GET', `/api/messages/${msg.id}`)
139→          if (updated.status === 'answered') {
140→            return { content: [{ type: 'text', text: `Supervisor answered: ${updated.answer}` }] }
141→          }
142→        }
143→
144→        return {
145→          content: [{ type: 'text', text: 'No answer received in time. Make your best judgment and proceed.' }],
146→        }
147→      }
148→
149→      case 'delegate': {
150→        const result = await api('POST', '/api/delegate', {
151→          fromAgentId: AGENT_ID,
152→          toAgentId: a.agent_id,
153→          missionId: MISSION_ID,
154→          task: a.task,
155→          workspace: a.workspace,
156→        })
157→        return {
158→          content: [{ type: 'text', text: `Delegated to ${a.agent_id}. Sub-mission: ${result.subMissionId}. Waiting for completion...` }],
159→        }
160→      }
161→
162→      case 'report': {
163→        await api('POST', '/api/messages', {
164→          from: AGENT_ID,
165→          missionId: MISSION_ID,
166→          type: 'report',
167→          summary: a.summary,
168→          artifacts: a.artifacts ?? [],
169→        })
170→        return {
171→          content: [{ type: 'text', text: `Report submitted. Mission ${MISSION_ID} marked complete.` }],
172→        }
173→      }
174→
175→      case 'memory_read': {
176→        const memPath = join(AGENTS_DIR, AGENT_ID, 'memory.md')
177→        const content = await readFile(memPath, 'utf-8').catch(() => '(empty)')
178→        return { content: [{ type: 'text', text: content }] }
179→      }
180→
181→      case 'memory_write': {
182→        const memPath = join(AGENTS_DIR, AGENT_ID, 'memory.md')
183→        const existing = await readFile(memPath, 'utf-8').catch(() => '')
184→        const timestamp = new Date().toISOString()
185→        await writeFile(memPath, `${existing}\n\n## ${timestamp}\n${a.content}`)
186→        return { content: [{ type: 'text', text: 'Memory saved.' }] }
187→      }
188→
189→      case 'cross_team_delegate': {
190→        // Check caller's rank — only director+ can cross-team delegate
191→        let callerProfile: Record<string, unknown> = {}
192→        try {
193→          const profilePath = join(AGENTS_DIR, AGENT_ID, 'profile.json')
194→          callerProfile = JSON.parse(await readFile(profilePath, 'utf-8'))
195→        } catch {}
196→
197→        const rank = (callerProfile.rank as string) ?? 'member'
198→        if (rank !== 'director' && rank !== 'executive') {
199→          return {
200→            content: [{ type: 'text', text: 'Error: Only agents with rank "director" or "executive" can delegate cross-team. Your rank: ' + rank }],
201→            isError: true,
202→          }
203→        }
204→
205→        // Find the target team's head
206→        let targetTeam: Record<string, unknown> = {}
207→        try {
208→          const teamRes = await api('GET', `/api/teams/${a.to_team}`)
209→          targetTeam = teamRes
210→        } catch {}
211→
212→        const targetHead = targetTeam.head as string
213→        if (!targetHead) {
214→          return {
215→            content: [{ type: 'text', text: `Error: Team "${a.to_team}" not found or has no head.` }],
216→            isError: true,
217→          }
218→        }
219→
220→        // Create a cross-team message
221→        await api('POST', '/api/messages', {
222→          from: AGENT_ID,
223→          missionId: MISSION_ID,
224→          type: 'escalate',
225→          question: `[Cross-team from ${callerProfile.team ?? 'unknown'}] Task: ${a.task}\n\nWhy: ${a.why}\nKnown: ${a.known ?? 'N/A'}\nExpected output: ${a.expected_output}`,
226→          context: `Cross-team delegation to ${a.to_team}`,
227→          to: targetHead,
228→        })
229→
230→        // Delegate the task to the target head
231→        const result = await api('POST', '/api/delegate', {
232→          fromAgentId: AGENT_ID,
233→          toAgentId: targetHead,
234→          missionId: MISSION_ID,
235→          task: `[Cross-team request from ${callerProfile.title ?? AGENT_ID}]\n\nTask: ${a.task}\nWhy: ${a.why}\nKnown context: ${a.known ?? 'N/A'}\nExpected output: ${a.expected_output}`,
236→        })
237→
238→        return {
239→          content: [{ type: 'text', text: `Cross-team task delegated to ${targetHead} (${a.to_team}). Sub-mission: ${result.subMissionId}` }],
240→        }
241→      }
242→
243→      default:
244→        return { content: [{ type: 'text', text: `Unknown tool: ${name}` }], isError: true }
245→    }
246→  } catch (err) {
247→    return {
248→      content: [{ type: 'text', text: `Tool error: ${(err as Error).message}` }],
249→      isError: true,
250→    }
251→  }
252→})
253→
254→const transport = new StdioServerTransport()
255→await server.connect(transport)
256→

