          </div>

          <div className="mt-4 flex flex-wrap items-center gap-2">
            {(['tasks', 'inbox', 'agents', 'chat'] as const).map((t) => (
              <button key={t} onClick={() => setTab(t)} className={`tab-chip ${tab === t ? 'active' : ''}`}>
                {t}
