                                          if (next.has(msg.id)) next.delete(msg.id)
                                          else next.add(msg.id)
                                          return next
                                        })
                                      }
                                      className="mt-1.5 text-xs font-semibold text-[#4a8a5e] hover:text-[#2d6040]"
                                    >
                                      {isExpanded ? 'Hide' : `${replies.length}`} {replies.length === 1 ? 'reply' : 'replies'}
